prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?midType ?midValue ?choreo ?elem ?name {
  ?model a bboExt:Model .
  OPTIONAL { ?model tai:normalizedId ?midValue . BIND("normalizedId" AS ?midType) }
  OPTIONAL { ?model tai:originalId ?midValue . BIND("originalId" AS ?midType) }
  FILTER(?midValue = "0b21c69687b64d8886fb7cc5dc56ff6c")

  ?def tai:belongsTo ?model .
  ?choreo tai:belongsTo ?def .
  ?elem tai:belongsTo ?choreo .
  OPTIONAL { ?elem bbo:name ?name . }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?task ?taskId ?name ?loopType WHERE {
  BIND("https://www.teamingai-project.eu/kg/model/sid_32ebd244_789a_4034_845b_7909f514afae" AS ?model)
  ?def tai:belongsTo ?model .
  ?choreo tai:belongsTo ?def .
  ?task tai:belongsTo ?choreo .
  ?task a bboExt:ChoreographyTask .
  OPTIONAL { ?task bbo:id ?taskId . }
  OPTIONAL { ?task bbo:name ?name . }
  OPTIONAL { ?task bboExt:loopType ?loopType . }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?s ?p ?o WHERE {
  BIND("https://www.teamingai-project.eu/kg/model/sid_32ebd244_789a_4034_845b_7909f514afae" AS ?model)
  { ?s tai:belongsTo ?model . BIND(1 AS ?k) }
  UNION
  { ?s tai:belongsTo ?any . ?any tai:belongsTo ?model . BIND(2 AS ?k) }
  UNION
  { ?s ?p ?model . BIND(3 AS ?k) }
  BIND(?k AS ?oType)
}
LIMIT 25
